        int t1 = upper_bound(sr.begin(),sr.end(),P[i].l) - sr.begin();

        int t2 = lower_bound(sl.begin(),sl.end(),P[i].r) - sl.begin();

        t2 = n - t2;

        mmax = max(mmax,n - t1 - t2);

    }

    sort(P, P + n);

    multiset<int> s;

    multiset<int>::iterator it;

    for(int i = 0; i < n; i++) {

        if(s.empty()) {

            s.insert(-P[i].r);

        } else {

            it = s.lower_bound(-P[i].l);

            if(it == s.end()) {

                s.insert(-P[i].r);

            } else {

                s.erase(it);

                s.insert(-P[i].r);

            }

        }

    }

    cout << mmax << " " << s.size() << endl;

    return 0;

}

